import React, { useEffect } from "react";
import { Table } from "antd";
import { useDispatch, useSelector } from "react-redux";

import { Link } from "react-router-dom";
import { config } from "../../utils/axiosconfig";
import { getOrders, updateAOrder } from "../../features/auth/authSlice";
const columns = [
    {
        title: "SNo",
        dataIndex: "key",
    },
    {
        title: "Name",
        dataIndex: "name",
    },
    {
        title: "Product",
        dataIndex: "product",
    },
    {
        title: "Amount",
        dataIndex: "amount",
    },
    {
        title: "Date",
        dataIndex: "date",
    },

    {
        title: "Action",
        dataIndex: "action",
    },
];

const Orders = () => {
    const dispatch = useDispatch();
    useEffect(() => {
        dispatch(getOrders(config));
    }, []);
    

    const user = useSelector((state) => state?.auth?.user);
    //console.log("User ID:", user);

    const orderState = useSelector((state) => state?.auth?.orders.orders);
    
    const filteredOrders = orderState?.filter(
        (order) =>
            order?.orderStatus === "delivered" &&
            order?.cart?.some((item) => item.postedByUserId === user?._id)
    );

    const data1 = [];
    for (let i = 0; i < filteredOrders?.length; i++) {
        data1.push({
            key: i + 1,
            name: filteredOrders[i]?.user?.firstname,
            product: (
                <Link to={`${filteredOrders[i]?._id}`}>View Orders</Link>
            ),
            amount: filteredOrders[i]?.totalPrice,
            date: new Date(filteredOrders[i]?.createdAt).toLocaleString(),
            action: filteredOrders[i]?.orderStatus,
        });
    }

    const updateOrderStatus = (a, b) => {
        dispatch(updateAOrder({ id: a, status: b }));
    };
    return (
        <div>
            <h3 className="mb-4 title">Orders</h3>
            <div>{<Table columns={columns} dataSource={data1} />}</div>
        </div>
    );
};

export default Orders;
